module top_module(
    input [7:0] A,
    input [7:0] B,
    input add,
    input sub,
    output [7:0] Z
);reg [7:0] result;

    always @(*) begin
        if (add) begin
            result = A + B;
        end
        else if (sub) begin
            result = A - B;
        end
        else begin
            result = 8'b0;
        end
    end

    assign Z = result;

endmodule
